import React, { useState, useEffect } from "react";
import { PRIORITY_META, STATUS_META, formatDate } from "../utils/costants";

export default function FeatureCard({ feature, onViewDetails }) {
  const [lightboxOpen, setLightboxOpen] = useState(false);
  const pm = PRIORITY_META[feature.priority];
  const sm = STATUS_META[feature.status];

  // Close lightbox on Escape
  useEffect(() => {
    if (!lightboxOpen) return;
    const handler = (e) => { if (e.key === "Escape") setLightboxOpen(false); };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [lightboxOpen]);

  return (
    <>
      <article
        className="card"
        onClick={() => onViewDetails(feature)}
        style={{ cursor: "pointer" }}
        title="Click to view details"
      >
        <div className="card-top">
          <span className="priority-badge" style={{ "--badge-color": pm.color }}>
            {feature.priority}
          </span>
          <span className="card-date">{formatDate(feature.createdAt)}</span>
        </div>

        <h3 className="card-title">{feature.title}</h3>
        <p className="card-desc">{feature.description}</p>

        {/* Image thumbnail — click opens lightbox, does NOT open detail modal */}
        {feature.imageUrl && (
          <div style={{ position: "relative", marginTop: 8 }}>
            <img
              src={feature.imageUrl}
              alt={feature.title}
              className="card-image"
              onClick={(e) => {
                e.stopPropagation();      // prevent card → detail modal
                setLightboxOpen(true);
              }}
              style={{ cursor: "zoom-in", width: "100%", borderRadius: "var(--radius)", display: "block" }}
              title="Click to view full image"
            />
            <div style={{
              position: "absolute", bottom: 6, right: 8,
              fontSize: 11, color: "#fff",
              background: "rgba(0,0,0,0.5)",
              padding: "2px 7px", borderRadius: 4,
              pointerEvents: "none",
            }}>
              🔍 Click to enlarge
            </div>
          </div>
        )}

        <div className="card-footer">
          <span className={`status-btn status-${feature.status.replace(" ", "-").toLowerCase()}`}>
            <span className="status-icon">{sm.icon}</span>
            {sm.label}
          </span>
          <span style={{ fontSize: 12, color: "var(--text-3)" }}>
            View details →
          </span>
        </div>
      </article>

      {/* Lightbox — rendered outside the card so it covers the full screen */}
      {lightboxOpen && feature.imageUrl && (
        <div
          onClick={() => setLightboxOpen(false)}
          style={{
            position: "fixed", inset: 0,
            background: "rgba(0,0,0,0.92)",
            zIndex: 10000,
            display: "flex", alignItems: "center", justifyContent: "center",
            padding: 20, cursor: "zoom-out",
            backdropFilter: "blur(6px)",
          }}
        >
          {/* Close button */}
          <button
            onClick={() => setLightboxOpen(false)}
            style={{
              position: "absolute", top: 20, right: 20,
              background: "rgba(255,255,255,0.15)", color: "#fff",
              border: "1px solid rgba(255,255,255,0.2)",
              borderRadius: "50%", width: 40, height: 40,
              fontSize: 18, cursor: "pointer",
              display: "flex", alignItems: "center", justifyContent: "center",
            }}
          >✕</button>

          <img
            src={feature.imageUrl}
            alt="Full size"
            onClick={(e) => e.stopPropagation()}   // clicking image itself doesn't close
            style={{
              maxWidth: "90vw", maxHeight: "90vh",
              objectFit: "contain", borderRadius: 8,
              boxShadow: "0 8px 48px rgba(0,0,0,0.7)",
              cursor: "default",
            }}
          />
        </div>
      )}
    </>
  );
}
